export default "/* inlined from ../_variables.css */\n:host {\n  --theme-bg: hsl(0 0% 100%);\n  --theme-bd: hsl(0 0% 100% / .8);\n  --theme-bd-2: hsl(0 0% 100% / .9);\n  --theme-color: hotpink;\n  --theme-blue: hsl(188 90% 45%);\n  --theme-purple: hsl(267 100% 58%);\n\n  --theme-text_color: hsl(0 0% 10%);\n  --theme-icon_color: hsl(0 0% 20%);\n  --theme-icon_hover-bg: hsl(0 0% 95%);\n  --theme-icon_active-bg: hsl(0 0% 90%);\n\n  --layer-top: 2147483647;\n  --layer-1: 2147483646;\n  --layer-2: 2147483645;\n  --layer-3: 2147483644;\n  --layer-4: 2147483643;\n  --layer-5: 2147483642;\n\n  @media (prefers-color-scheme: dark) {\n    --theme-bg: hsl(0 0% 10%);\n    --theme-bd: hsl(0 0% 10% / .8);\n    --theme-bd-2: hsl(0 0% 10% / .9);\n\n    --theme-text_color: hsl(0 0% 80%);\n    --theme-icon_color: hsl(0 0% 60%);\n    --theme-icon_hover-bg: hsl(0 0% 15%);\n    --theme-icon_active-bg: hsl(0 0% 20%);\n  }\n}\n\n\n:host {\n  position: absolute;\n  z-index: var(--layer-top);\n\n  --arrow-width: 15px;\n  --arrow-height: 8px;\n\n  --shadow-up: 5px;\n  --shadow-down: -5px;\n  --shadow-direction: var(--shadow-up);\n\n  --arrow-up: polygon(0 0, 100% 0, 50% 100%);\n  --arrow-down: polygon(50% 0, 0 100%, 100% 100%);\n  --arrow: var(--arrow-up);\n}\n\n:host figure {\n  all: initial;\n  direction: ltr;\n  font-size: 16px;\n  font-family: system-ui;\n  max-width: 50vw;\n  background: var(--theme-bd);\n  backdrop-filter: blur(5px);\n  color: var(--theme-text_color);\n  line-height: initial;\n  padding: 0.5em;\n  margin: 0;\n  display: flex;\n  flex-direction: column;\n  flex-wrap: nowrap;\n  border-radius: 0.25em;\n  line-height: initial;\n  filter: drop-shadow(0 var(--shadow-direction) 0.5em hsla(0,0%,0%,35%));\n\n  border: 1px solid var(--theme-bg);\n  &:after {\n    content: \"\";\n    background: var(--theme-bg);\n    width: var(--arrow-width);\n    height: var(--arrow-height);\n    clip-path: var(--arrow);\n    position: absolute;\n    top: var(--arrow-top);\n    left: var(--arrow-left);\n  }\n\n  & a {\n    text-decoration: none;\n    color: inherit;\n    text-overflow: ellipsis;\n    overflow: hidden;\n    cursor: pointer;\n\n    &:hover {\n      color: var(--theme-color);\n      text-decoration: underline;\n    }\n\n    &:empty {\n      display: none;\n    }\n\n    &[node]:before {\n      content: \"\\003c\";\n    }\n\n    &[node]:after {\n      content: \"\\003e\";\n    }\n  }\n}\n\n:host h5 {\n  display: flex;\n  font-size: 1em;\n  font-weight: bolder;\n  margin: 0;\n  overflow: hidden;\n  white-space: nowrap;\n}\n\n:host h6 {\n  margin-top: 1em;\n  margin-bottom: 0;\n  font-weight: normal;\n}\n\n:host small {\n  font-size: 0.7em;\n  color: var(--theme-icon_color);\n\n  & > span {\n    color: hsl(0,0%,20%);\n  }\n}\n\n:host a:not(:hover) {\n  text-decoration: none;\n}\n\n:host [brand],\n:host [divider] {\n  color: var(--theme-color);\n}\n\n:host div {\n  display: grid;\n  grid-template-columns: auto auto;\n  grid-gap: 0.25em 0.5em;\n  margin: 0.5em 0 0;\n  padding: 0;\n  list-style-type: none;\n  color: var(--theme-icon_color);\n  font-size: 0.8em;\n  font-family: 'Dank Mono', 'Operator Mono', 'Inconsolata', 'Fira Mono', 'SF Mono', 'Monaco', 'Droid Sans Mono', 'Source Code Pro', monospace;\n}\n\n:host [value],\n:host [local-change] {\n  color: var(--theme-text_color);\n  display: inline-grid;\n  grid-auto-flow: column;\n  gap: .5em;\n  align-items: center;\n  justify-content: flex-end;\n  text-align: right;\n  /* white-space: pre; */\n}\n\n:host [text] {\n  white-space: normal;\n}\n\n:host [longform] {\n  background: var(--theme-icon_hover-bg);\n  padding: 0.5em 0.75em;\n  border-radius: 0.25em;\n  font-family: sans-serif;\n  text-align: left;\n  line-height: 1.5;\n}\n\n:host [color] {\n  position: relative;\n  top: 1px;\n  display: inline-block;\n  width: 1em;\n  min-width: 1em;\n  height: 1em;\n  border-radius: 50%;\n}\n\n:host [local-modifications] {\n  margin-top: 1rem;\n  color: var(--theme-color);\n  font-weight: bold;\n\n  & + div {\n    margin-bottom: 1em;\n  }\n}\n\n:host [contrast] > span {\n  padding: 0 0.5em 0.1em;\n  border-radius: 1em;\n  box-shadow: 0 0 0 1px var(--theme-icon_active-bg);\n}\n";
